('02',"s", "<div class='photo p1'><img src='assets/photo1.jpg'></div><div class='shade'></div><div class='glow'></div><div class='halftone'></div><div class='logo'><img src='assets/logo-dark.svg'></div><div class='content right mid'><div class='kicker'>01 · corpo</div><h2>ANTES<br>DO SOM<br><span class='outline'>SAIR</span></h2><div class='body'>A mão prepara. O peito responde. O palco sente.</div></div><div class='plus'><span>+</span><span>+</span><span>+</span><span>+</span><span>+</span><span>+</span></div>"),
('03',"s light", "<div class='halftone'></div><div class='la center'><img src='assets/la-solo-light.svg'></div><div class='logo'><img src='assets/logo-light.svg'></div><div class='num n1'>02</div><div class='content center'><div class='kicker'>técnica com intenção</div><h2 class='huge lightTitle'>NÃO É<br><span class='outline'>BATER</span><br>MAIS FORTE</h2><div class='body'>É tocar com controle: tempo, dinâmica, pegada e consciência.</div></div>"),
('04',"s", "<div class='photo p3'><img src='assets/photo3.jpg'></div><div class='shade left' style='background:linear-gradient(90deg,rgba(0,0,0,.86),rgba(0,0,0,.48) 44%,rgba(0,0,0,.12)),linear-gradient(180deg,rgba(0,0,0,.45),rgba(0,0,0,.04) 35%,rgba(0,0,0,.78))'></div><div class='glow'></div><div class='halftone left'></div><div class='logo'><img src='assets/logo-dark.svg'></div><div class='content leftText mid'><div class='kicker'>03 · foco</div><h2>O FOCO<br><span class='outline'>TAMBÉM</span><br>TOCA</h2><div class='body'>Disciplina vira linguagem. Linguagem vira identidade.</div></div>"),
