('06',"s", "<div class='photo p1'><img src='assets/photo1.jpg'></div><div class='shade left'></div><div class='glow'></div><div class='halftone left'></div><div class='la right'><img src='assets/la-solo.svg'></div><div class='logo'><img src='assets/logo-dark.svg'></div><div class='content leftText lower' style='bottom:235px'><div class='kicker'>04 · palco</div><h2 class='small' style='font-size:70px'>LUZ ACESA.<br>BAQUETAS<br><span class='pinkword'>NO ALTO.</span></h2><div class='body'>Aqui você aprende a tocar como quem tem algo a dizer.</div></div>"),
