htmls=[]
for code, cls, body in slides:
    html=f"<!doctype html><html><head><meta charset='utf-8'><style>{CSS}</style></head><body><section class='{cls}'>{body}{footer()}</section></body></html>"
    p=OUT/f'slide-{code}.html'; p.write_text(html); htmls.append((code,p))
chromium='/usr/local/bin/chromium'
for code,p in htmls:
    subprocess.run([chromium,'--headless','--no-sandbox','--disable-gpu','--window-size=1080,1440',f'--screenshot={PNG/f"la-school-batida-{code}.png"}',p.as_uri()],check=True,stdout=subprocess.PIPE,stderr=subprocess.PIPE)
imgs=[]
for code,p in htmls:
    im=Image.open(PNG/f'la-school-batida-{code}.png').convert('RGB')
    im=ImageOps.fit(im,(270,360)); imgs.append(im)
canvas=Image.new('RGB',(1080,720),(17,17,17))
for i,im in enumerate(imgs): canvas.paste(im,((i%4)*270,(i//4)*360))
canvas.save(OUT/'preview-grid.jpg',quality=92)
(OUT/'LAHQ_PIPELINE.md').write_text('''# LAHQ Pipeline — A batida que faz o chão tremer\n\nMarca: LA Music School\nFormato: 8 lâminas 1080x1440\nSkill usada: lahq-school-content\nFotos reais: alunos em show / bateria\n\n## Nina\nConceito: transformar fotos reais de alunos em narrativa de manifesto sobre bateria, presença de palco, técnica e alma.\n\n## Theo\nCopy curta, forte e aspiracional: batida, chão, corpo, foco, groove, palco, chamado e CTA.\n\n## Luna\nUsar 4 fotos reais; preservar rosto, instrumento, baquetas e contexto de show. Sem IA genérica.\n\n## Diego\nAplicar DS School: Prompt pesada, logo oficial, halftone, LA solo como composição apenas em áreas seguras, dark/pink/light alternado, footer pill.\n\n## QA\nChecar: logo oficial, foto real preservada, LA não cobre rosto/microfone/baquetas, card pink não vira muleta, legibilidade mobile e cara de campanha real.\n''')
subprocess.run(['tar','-czf',str(OUT.with_suffix('.tar.gz')),'-C',str(OUT.parent),OUT.name],check=True)
